+    #[test]
+    fn api_negative_code_to_fcp_error_status_code_none() {
+        let err = DiscordError::Api {
+            code: -1,
+            message: "unknown".into(),
+            retry_after: None,
+        };
+        let fcp = err.to_fcp_error();
+        match fcp {
+            FcpError::External { status_code, .. } => {
+                // u16::try_from(-1) fails → None
